module top_module (
	input clk,
	input reset,
	input load,
	input [15:0] data,
	output reg [15:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
		if (reset)
			q <= 16'b0000000000000000;
		else if (load)
			q <= data;
		else
			q <= q << 1;
	end

endmodule
